const AWS = require('aws-sdk');
const s3 = new AWS.S3({ apiVersion: '2006-03-01' });

exports.handler = async (event) => {
    // Validate S3 event
    if (!event.Records || !event.Records[0]) {
        throw new Error('Invalid S3 event');
    }

    const record = event.Records[0];
    const bucket = record.s3.bucket.name;
    const key = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
    
    // Validate input
    if (!bucket || !key) {
        throw new Error('Missing bucket or key in S3 event');
    }

    // Validate file extension (whitelist)
    const allowedExtensions = ['.txt', '.pdf', '.docx', '.xlsx'];
    const fileExtension = key.substring(key.lastIndexOf('.')).toLowerCase();
    if (!allowedExtensions.includes(fileExtension)) {
        throw new Error('Invalid file extension');
    }

    try {
        // Read file from S3
        const s3Params = {
            Bucket: bucket,
            Key: key
        };

        const fileData = await s3.getObject(s3Params).promise();
        
        // Process file (example: convert to uppercase)
        let processedData;
        if (fileData.ContentType === 'application/pdf') {
            // Handle PDF processing
            processedData = Buffer.from('PDF processed: ' + key);
        } else {
            // Handle text processing
            const originalContent = fileData.Body.toString('utf-8');
            processedData = Buffer.from(originalContent.toUpperCase());
        }

        // Generate output key using original filename
        const outputKey = key.replace(/(\.[^/.]+)$/, '-processed$1');

        // Save processed file to S3
        const outputParams = {
            Bucket: process.env.OUTPUT_BUCKET,
            Key: outputKey,
            Body: processedData,
            ContentType: fileData.ContentType
        };

        await s3.putObject(outputParams).promise();
        
        return {
            statusCode: 200,
            body: JSON.stringify({
                message: 'File processed successfully',
                inputKey: key,
                outputKey: outputKey
            })
        };
    } catch (error) {
        console.error('Error processing file:', error);
        throw error;
    }
};